import React from 'react';
import { Formik, Form, Field, ErrorMessage } from 'formik';

function AddPost() {
  return (
    <div className='addPostPage'>
        <Formik >
            <Form>
                <label>Title:</label>
                <Field id="inputCreatePost" name="title" placeholder="Enter your title" />
                <label>Post:</label>
                <Field id="inputCreatePost" name="postText" placeholder="Enter your post" />
                <label>Name:</label>
                <Field id="inputCreatePost" name="username" placeholder="Enter your name" />
            </Form> 
        </Formik>
    </div>
  )
}

export default AddPost
